"use client";

import { useState, useEffect } from "react";
import { ShoppingCart, Loader2, ArrowLeft, Plus, Minus } from "lucide-react";
import Link from "next/link";
import api from "@/lib/api/axios";
import { toast } from "sonner";

interface CartEvent {
  product_id: number;
  total_quantity: string | number;
  product: {
    id: number;
    name: string;
    slug: string;
    price: string;
  };
}

interface CartSummary {
  total_events: number;
  items_added: string | number;
  items_removed: number;
  by_event_type: {
    added?: number;
    removed?: number;
  };
  most_added_products: CartEvent[];
}

export default function CartEventsPage() {
  const [summary, setSummary] = useState<CartSummary | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchCartEvents();
  }, []);

  const fetchCartEvents = async () => {
    try {
      setLoading(true);
      const token = localStorage.getItem("token");

      const response = await api.get("/api/admin/analytics/cart-events", {
        headers: token ? { Authorization: `Bearer ${token}` } : {},
      });

      if (response.data.success) {
        const data = response.data.data;
        
        if (data && typeof data === 'object') {
          setSummary(data);
        } else {
          setSummary(null);
        }
      } else {
        setSummary(null);
        toast.error(response.data.message || "Failed to load cart events");
      }
    } catch (error: any) {
      console.error("Error fetching cart events:", error);
      setSummary(null);
      
      const errorMessage = error.response?.data?.message || error.message || "Failed to load cart events";
      toast.error(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex min-h-screen items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <div className="mb-6">
        <Link
          href="/admin/analytics"
          className="mb-4 inline-flex items-center gap-2 text-sm text-gray-600 hover:text-gray-900"
        >
          <ArrowLeft className="h-4 w-4" />
          Back to Dashboard
        </Link>
        <div className="flex items-center gap-3">
          <div className="rounded-full bg-orange-100 p-3">
            <ShoppingCart className="h-6 w-6 text-orange-600" />
          </div>
          <div>
            <h1 className="text-3xl font-bold text-gray-900">Cart Events</h1>
            <p className="text-sm text-gray-500">Items added and removed from cart</p>
          </div>
        </div>
      </div>

      {/* Summary Cards */}
      <div className="mb-6 grid gap-6 md:grid-cols-3">
        <div className="rounded-lg bg-white p-6 shadow-sm">
          <p className="text-sm font-medium text-gray-500">Total Events</p>
          <p className="mt-2 text-3xl font-bold text-gray-900">{summary?.total_events || 0}</p>
        </div>
        <div className="rounded-lg bg-white p-6 shadow-sm">
          <div className="flex items-center gap-2">
            <Plus className="h-5 w-5 text-green-600" />
            <p className="text-sm font-medium text-gray-500">Items Added</p>
          </div>
          <p className="mt-2 text-3xl font-bold text-green-600">{summary?.items_added || 0}</p>
        </div>
        <div className="rounded-lg bg-white p-6 shadow-sm">
          <div className="flex items-center gap-2">
            <Minus className="h-5 w-5 text-red-600" />
            <p className="text-sm font-medium text-gray-500">Items Removed</p>
          </div>
          <p className="mt-2 text-3xl font-bold text-red-600">{summary?.items_removed || 0}</p>
        </div>
      </div>

      {/* Most Added Products */}
      <div className="rounded-lg bg-white shadow-sm">
        <div className="border-b border-gray-200 px-6 py-4">
          <h2 className="text-lg font-semibold text-gray-900">Most Added Products</h2>
        </div>
        {!summary || !summary.most_added_products || summary.most_added_products.length === 0 ? (
          <div className="flex flex-col items-center justify-center p-12 text-center">
            <ShoppingCart className="h-12 w-12 text-gray-400" />
            <h3 className="mt-4 text-lg font-semibold text-gray-900">No Cart Events</h3>
            <p className="mt-2 text-sm text-gray-500">
              No cart activity recorded yet. Data will appear here once customers start adding items to cart.
            </p>
            <button
              onClick={fetchCartEvents}
              className="mt-4 rounded-lg bg-primary px-4 py-2 text-sm font-medium text-black hover:bg-primary/90"
            >
              Refresh
            </button>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead className="border-b border-gray-200 bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium uppercase tracking-wider text-gray-500">
                    Product
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium uppercase tracking-wider text-gray-500">
                    Price
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium uppercase tracking-wider text-gray-500">
                    Times Added
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200 bg-white">
                {summary.most_added_products.map((item) => (
                  <tr key={item.product_id} className="hover:bg-gray-50">
                    <td className="px-6 py-4">
                      <div className="text-sm font-medium text-gray-900">{item.product.name}</div>
                      <div className="text-xs text-gray-500">{item.product.slug}</div>
                    </td>
                    <td className="whitespace-nowrap px-6 py-4 text-sm text-gray-900">
                      KES {parseFloat(item.product.price).toLocaleString()}
                    </td>
                    <td className="whitespace-nowrap px-6 py-4">
                      <span className="inline-flex items-center gap-1 rounded-full bg-green-100 px-3 py-1 text-sm font-semibold text-green-800">
                        <Plus className="h-3 w-3" />
                        {item.total_quantity}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}
